const newItems = [];
const seenFiles = new Set();   // ← Prevent duplicate file names

for (const item of items) {
	if (item.binary) {
		for (const key of Object.keys(item.binary)) {
			const file = item.binary[key];

			// Skip invalid or duplicated files
			if (!file || !file.fileName || seenFiles.has(file.fileName)) continue;

			seenFiles.add(file.fileName); // Mark as seen

			newItems.push({
				json: {
					original_binary_key: key,
					file_name: file.fileName,
					mime_type: file.mimeType,
					file_size: file.fileSize,
				},
				binary: {
					data: file, // renaming key → data
				},
			});
		}
	}
}

return newItems;

